import { GoogleGenAI, GenerateContentResponse, Type } from "@google/genai";
import { FactCheckResult, VerdictType, Source, TickerItem } from "../types";
import { db } from "./db";

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

// --- UTILS ---

const retryOperation = async <T>(operation: () => Promise<T>, retries = 2, delay = 1000): Promise<T> => {
  for (let i = 0; i < retries; i++) {
    try {
      return await operation();
    } catch (error) {
      if (i === retries - 1) throw error;
      await new Promise(resolve => setTimeout(resolve, delay * (i + 1)));
    }
  }
  throw new Error("Operation failed after retries");
};

/**
 * Robust JSON extractor that finds the most likely JSON block in a string.
 * It searches for the outermost matching pairs of brackets [] or braces {}.
 * This prevents errors when the model includes extra text or grounding citations in the response.
 */
const cleanJsonString = (text: string): string => {
  if (!text) return "";

  // Find first occurrence of [ or {
  const startIndex = text.search(/[\[\{]/);
  if (startIndex === -1) return text.trim();

  // Find last occurrence of ] or }
  const lastBracket = text.lastIndexOf(']');
  const lastBrace = text.lastIndexOf('}');
  const endIndex = Math.max(lastBracket, lastBrace);

  if (endIndex === -1 || endIndex < startIndex) return text.trim();

  return text.substring(startIndex, endIndex + 1).trim();
};

const getNewsImage = (keyword: string): string => {
  const seed = encodeURIComponent(keyword.substring(0, 15));
  return `https://picsum.photos/seed/${seed}/800/450`;
};

// --- API CALLS ---

export const fetchRealTopNews = async (): Promise<TickerItem[]> => {
    try {
        const response = await ai.models.generateContent({
            model: "gemini-3-flash-preview",
            contents: [{ 
              parts: [{ 
                text: "Search for the top 5 most important global news headlines from the last 24 hours. For each, determine if it is a verified fact (TRUE) or a debunked rumor (FALSE). Return as a JSON array: [{\"headline\":\"...\", \"verdict\":\"TRUE\"|\"FALSE\", \"source\":\"...\"}]" 
              }] 
            }],
            config: { 
                tools: [{ googleSearch: {} }],
                temperature: 0.1,
                responseMimeType: "application/json"
            }
        });

        const text = response.text || "";
        const cleaned = cleanJsonString(text);
        const data = JSON.parse(cleaned);

        if (Array.isArray(data)) {
            db.saveTicker(data);
            return data;
        }
    } catch (e) {
        console.error("Ticker fetch error:", e);
    }
    return db.getTicker();
};

export const fetchTrendingDebunks = async (forceRefresh = false): Promise<FactCheckResult[]> => {
  if (!forceRefresh && !db.isCacheStale()) {
    const cached = db.getTrending();
    if (cached.length > 0) return cached;
  }

  try {
     const response = await ai.models.generateContent({
      model: "gemini-3-flash-preview",
      contents: [{ 
        parts: [{ 
          text: "Identify 4 currently trending internet rumors or viral social media claims. Provide a mix of verified truths and debunked myths. Return as a JSON array of objects with keys: headline, summary, verdict (TRUE/FALSE/MISLEADING), and sourceName." 
        }] 
      }],
      config: {
        tools: [{ googleSearch: {} }],
        temperature: 0.4,
        responseMimeType: "application/json"
      }
    });

    const cleaned = cleanJsonString(response.text || "[]");
    const data = JSON.parse(cleaned);
    const groundingChunks = response.candidates?.[0]?.groundingMetadata?.groundingChunks || [];
    const webSources: Source[] = groundingChunks
      .filter((c: any) => c.web?.uri)
      .map((c: any) => ({ title: c.web.title || "Reference", uri: c.web.uri }));

    const results: FactCheckResult[] = data.map((item: any, i: number) => {
      const total = 1000 + Math.floor(Math.random() * 5000);
      const verdict = item.verdict as VerdictType;

      return {
        id: `trend-${Date.now()}-${i}`,
        claim: item.headline,
        verdict: verdict,
        explanation: item.summary,
        headline: item.headline,
        keyPoints: ["Source verified via live search", "Contextual analysis complete"],
        sources: webSources.slice(i, i + 2).length > 0 ? webSources.slice(i, i + 2) : [{ title: item.sourceName || "News Wire", uri: "#" }],
        timestamp: Date.now(),
        confidenceScore: 85 + Math.floor(Math.random() * 14),
        communityPoll: {
            trueVotes: verdict === VerdictType.TRUE ? Math.floor(total * 0.9) : Math.floor(total * 0.1),
            falseVotes: verdict === VerdictType.FALSE ? Math.floor(total * 0.9) : Math.floor(total * 0.1),
            misleadingVotes: verdict === VerdictType.MISLEADING ? Math.floor(total * 0.8) : Math.floor(total * 0.05),
            total
        },
        author: "FactPulse AI",
        imageUrl: getNewsImage(item.headline)
      };
    });

    db.saveTrending(results);
    return results;
  } catch (e) {
    console.error("Trending fetch error:", e);
    return db.getTrending();
  }
}

export const analyzeClaim = async (
  text: string,
  imageBase64?: string
): Promise<Omit<FactCheckResult, 'id' | 'timestamp' | 'author'>> => {

  const parts: any[] = [];
  if (imageBase64) {
    parts.push({ inlineData: { data: imageBase64, mimeType: "image/jpeg" } });
  }

  parts.push({ 
    text: `Claim Analysis Request: "${text}". 
    Perform a deep web search. If this is a social media link (X, IG, FB), find external news reports about the content.
    Return a JSON object: { "verdict": "TRUE"|"FALSE"|"MISLEADING"|"UNVERIFIED", "headline": "...", "summary": "...", "keyPoints": ["...", "..."], "confidenceScore": 0-100 }`
  });

  try {
    const response = await retryOperation<GenerateContentResponse>(() => ai.models.generateContent({
      model: "gemini-3-pro-preview",
      contents: [{ parts }],
      config: {
        systemInstruction: "You are a world-class investigative journalist and fact-checker. Use Google Search to verify claims against reputable sources like Reuters, AP, and BBC. Always prioritize accuracy over speed. Return the analysis as a structured JSON object.",
        tools: [{ googleSearch: {} }],
        temperature: 0,
        responseMimeType: "application/json",
        thinkingConfig: { thinkingBudget: 4000 }
      }
    }));

    const cleaned = cleanJsonString(response.text || "{}");
    const jsonResponse = JSON.parse(cleaned);
    const groundingChunks: any[] = response.candidates?.[0]?.groundingMetadata?.groundingChunks || [];

    const uniqueSources: Source[] = Array.from(new Map<string, Source>(
      groundingChunks
        .filter((chunk: any) => chunk.web && chunk.web.uri)
        .map((chunk: any) => [
          chunk.web.uri as string, 
          { 
            title: (chunk.web.title as string) || "Verified Source", 
            uri: chunk.web.uri as string 
          }
        ])
    ).values());

    return {
      claim: text || "Image Analysis",
      verdict: (jsonResponse.verdict?.toUpperCase() as VerdictType) || VerdictType.UNVERIFIED,
      explanation: jsonResponse.summary || "Analysis complete.",
      headline: jsonResponse.headline || "Fact Check Result",
      keyPoints: jsonResponse.keyPoints || [],
      confidenceScore: jsonResponse.confidenceScore || 70,
      sources: uniqueSources,
      imageUrl: imageBase64 ? `data:image/jpeg;base64,${imageBase64}` : undefined,
      communityPoll: { trueVotes: 0, falseVotes: 0, misleadingVotes: 0, total: 0 },
    };
  } catch (error) {
    console.error("Deep Analysis Error:", error);
    throw error;
  }
};
